1	type Item = { type: string };
2	type Scenario = { steps: Array<{ op: string; items: Array<Item> }> };
3	
4	const PROCESSING_FEE = 5;
5	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	function quoteItem(item: Item): number {
17	  const basePremium = BASE_PREMIUMS[item.type];
18	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
19	  return basePremium + firstInsuranceSurcharge;
20	}
21	
22	export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
23	  const { steps } = scenario as Scenario;
24	  const itemsPremium = steps[0].items.reduce((sum, item) => sum + quoteItem(item), 0);
25	  const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
26	  return { results: [{ premium }] };
27	}
