const COMPONENT_TYPES = ["rune", "moonstone"];
const BLOCK_OF_THREE_BASE = 60;

export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
  const { steps } = scenario as Scenario;
  const items = steps[0].items;

  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }

  let itemsPremium = 0;
  const blockedTypes = new Set<string>();
  for (const componentType of COMPONENT_TYPES) {
    if (counts[componentType] === 3) {
      itemsPremium += BLOCK_OF_THREE_BASE * (1 + FIRST_INSURANCE_SURCHARGE_RATE);
      blockedTypes.add(componentType);
    }
  }

  for (const item of items) {
    if (blockedTypes.has(item.type)) continue;
    itemsPremium += quoteItem(item);
  }

  const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
  return { results: [{ premium }] };
}
